```c++
vector.cpp

#include <vector>
#include <iostream>
using namespace std;
int main()
{
    vector<int> num(10, 1);//10个1
    for (int i = 0; i < num.size(); i++)
    {
        if (i == 0)
            cout << num[i];
        else
            cout << "\t" << num[i];
    }
    cout << endl;
